<Variable name="main.menu.bg1" description="Main Menu Background 2" type="color" default="#cdb202" value="#202932"/>
<Variable name="main.menu.text.color" description="Main Menu Text Color" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="submenu.background.color" description="SubMenu Background Color" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="sub.menu.text.color" description="SubMenu Text Color" type="color" default="#3a3a3a" value="#313131"/>
<Variable name="main.logo.text.color" description="Main Logo Text Color" type="color" default="#222222" value="#000000"/>
</Group>
<Group description="Top Section Colors" selector="div.Super-MenuWorks">
<Variable name="color.section" description="Top Section Color 1" type="color" default="#e07c03" value="#03d4dc"/>
<Variable name="color.section1" description="Top Section Color 2" type="color" default="#cdb202" value="#0281c8"/>
<Variable name="color.section.text" description="Top Section Text Color" type="color" default="#ffffff" value="#ffffff"/>
</Group>
<Group description="Mobile Menu Colors" selector="div.Super-MenuWorks">
<Variable name="mobile.menu.bg.color" description="Mobile Menu Background Color" type="color" default="#ffffff" value="#ffffff"/>
</Group>
<Group description="Featured Gadgets Colors" selector="#feed-view">
<Variable name="featured.gadgets.title" description="Featured Gadgets Title" type="color" default="#e8e8e8" value="#e8e8e8"/>
<Variable name="featured.posts.title" description="Featured Posts Title" type="color" default="#333333" value="#262626"/>
