--placeholder-text-color:#dadada;
--theme-text-color:#dadada;
--featured-gadgets-title:#dadada;
--ads-bg:#212121;
--color-section:#1d1d1d;
--color-section1:#424242;
--footer-copyright-bg:#181818;
--box-posts-share:#323232;
--submenu-bg-color:#212121;
--label-text-color:#a1a1a1;
--featured-posts-title: #c3c3c3;
--ads-text:#dadada;
--buttons-category-text:#dadada;
--bg-cards:#212121;
--block-bg:#3a3a3a;
--black-text:#f3f8fb;
--post-snip-data:#555555;
--comments-dec:#cecece;
--comment-content:#353535;
--comment-text:#c1c1c1;
--footer-bg-color:#181818;
--footer-text-color:#E4E4E4;
--cm-count:#E4E4E4;
--main-text-color:#E4E4E4;
--nav-site-text:#c3c3c3;
--share-author-links:#E4E4E4;
--footer-copyright-bg:#292929;
}
a,abbr,acronym,address,applet,b,big,blockquote,body,caption,center,cite,code,dd,del,dfn,div,dl,dt,em,fieldset,font,form,h1,h2,h3,h4,h5,h6,html,i,iframe,img,ins,kbd,label,legend,li,object,p,pre,q,s,samp,small,span,strike,strong,sub,sup,table,tbody,td,tfoot,th,thead,tr,tt,u,ul,var{padding:0;border:0;outline:0;vertical-align:baseline;background:0;margin:0;text-decoration:none;}
form,textarea,input,button{font-family:var(--body-font);-webkit-appearance:none;-moz-appearance:none;appearance:none;border-radius:0;box-sizing:border-box}
input[type="radio"]{-webkit-appearance:auto;appearance:auto;}
.CSS_LIGHTBOX{z-index:999999!important}.CSS_LIGHTBOX_ATTRIBUTION_INDEX_CONTAINER .CSS_HCONT_CHILDREN_HOLDER > .CSS_LAYOUT_COMPONENT.CSS_HCONT_CHILD:first-child > .CSS_LAYOUT_COMPONENT{opacity:0}
input,textarea{outline:none;border: none;}
html{position:relative;word-break:break-word;word-wrap:break-word;text-rendering:optimizeLegibility;-webkit-font-smoothing:antialiased;-webkit-text-size-adjust:100%;}
/*! normalize.css v3.0.1 | MIT License | git.io/normalize */
dl,ul{list-style-position:inside;font-weight:400;list-style:none}
button{cursor: pointer;outline: none;border: none;}
ul li{list-style:none}
caption,th{text-align:center}
.box-view #outer-wrapper{max-width: 1190px;}
html,body{text-size-adjust:none;-webkit-text-size-adjust:none;-moz-text-size-adjust:none;-ms-text-size-adjust:none}
.separator a{clear:none!important;float:none!important;margin-left:0!important;margin-right:0!important}
#Navbar1,#navbar-iframe,.widget-item-control,a.quickedit,.home-link,.feed-links{display:none!important}
.center{display:table;margin:0 auto;position:relative}
.widget > h2,.widget > h3{display:none}
iframe[src*="youtube.com"]{width:100%;height:auto;aspect-ratio:16/9}
.widget iframe,.widget img{max-width:100%}
.post-body img:not(.snip-thumbnail){width:auto;height:auto;border:none;}
.container{position:relative;max-width: 100%;width: $(outerContainer.width);}
a,a:visited{text-decoration:none}
.clearfix{clear:both}
.section,.widget,.widget ul{margin:0;padding:0}
a{color:var(--all-link-color)}
abbr{text-decoration:none}
.widget>h2,.widget>h3{display:none}
*:before,*:after{-webkit-box-sizing:border-box;-moz-box-sizing:border-box;box-sizing:border-box;}
/*-- CSS Variables --*/
.no-items.section,#related-posts{display:none}
.cookie-choices-info{display:none !important;}
div#custom-ads-placeholder{display:none;}
.blogger-clickTrap{position:unset !important;}
h1,h2,h3,h4,h5,h6{font-family:var(--title-font);font-weight:600}
body{position:relative;background:var(--body-color-main);background-repeat:repeat;background-attachment: fixed;background-position:top;background-position:left;font-family:var(--body-font);font-size:14px;font-weight:400;color:var(--black-text);word-wrap:break-word;margin:0;padding:0;font-style:normal;line-height:1.4}
#outer-wrapper{position:relative;overflow:hidden;width:100%;max-width:100%;margin:0 auto}
.outer-container{display: flex;justify-content: space-between;}
.post-body h1{font-size:28px}
.post-body h2{font-size:24px}
.post-body h3{font-size:21px}
.post-body h4{font-size:18px}
.post-body h5{font-size:16px}
.post-body h6{font-size:13px}
.dark .post-body p{background:transparent!important;color:#fff!important}
.home #feed-view, .search-view #feed-view, .label-view #feed-view{width:100%}
#center-container{position:relative;float:left;width:100%;overflow:hidden;padding:10px 0 0;margin:0}
#feed-view{position:relative;float:left;width:calc(100% - ($(sidebar.width) + 5px));box-sizing:border-box;padding:0}
#sidebar-container{position:relative;float:right;width:$(sidebar.width);box-sizing:border-box;padding:0}
.post-filter-image{position:relative;display:block;transition:transform .3s ease}
.snip-thumbnail{position:relative;width:100%;height:100%;display:block;object-fit:cover;z-index:1;opacity:0;transition:opacity .30s ease,transform .30s ease}
#h1-hide{display:none;visibility:hidden}
h1.blog-title{font-size:24px;max-width:195px;overflow:hidden;text-decoration:none;text-overflow:ellipsis;white-space:nowrap;line-height: 38px;}
.snip-thumbnail.lazy-img{opacity:1}
.row{position:relative;}
.post-filter-link:hover .snip-thumbnail{filter: brightness(0.9);}
.background-layer:before{content:'';position:absolute;left:0;right:0;bottom:0;height:66%;background-image:linear-gradient(to bottom,transparent,rgba(0,0,0,0.80));-webkit-backface-visibility:hidden;backface-visibility:hidden;z-index:2;opacity:1;margin:0;transition:opacity .25s ease}
.kcode-icon a:before,.bpost-share a:before{display:inline-block;font-family:'Font Awesome 6 Brands';font-style:normal;font-weight:400;vertical-align: middle;}
.fa{font-family:'Font Awesome 6 Brands' !important;}
.kcode-icon .rss a:before,.social .rss a:before{content:'\e0e5';font-family:'Material Icons Round';}
.kcode-icon .email a:before,.social .email a:before{content:'\e158';font-family:'Material Icons Round';}
.kcode-icon .external-link a:before,.social .external-link a:before{content:'\e894';font-family:'Material Icons Round';}
.colorful a:hover {opacity: 0.8;}
.kcode-icon a:before{content:var(--fa);}
.colorful .blogger a{color:#ff5722}
.colorful .facebook a{color:#1877F2}
.colorful .twitter a{color:#00acee}
.colorful .youtube a{color:#f50000}
.colorful .messenger a{color:#0084ff}
.colorful .snapchat a{color:#ffe700}
.colorful .telegram a{color:#179cde}
.colorful .instagram a{color:#dd277b}
.colorful .pinterest a{color:#ca2127}
.colorful .google a{color:#0165b4}
.colorful .apple a{color:#000000}
.colorful .microsoft a{color:#0165b4}
.colorful .dribbble a{color:#ea4c89}
.colorful .linkedin a{color:#0077b5}
.colorful .tiktok a{color:#fe2c55}
.colorful .stumbleupon a{color:#eb4823}
.colorful .vk a{color:#4a76a8}
.colorful .stack-overflow a{color:#f48024}
.colorful .github a{color:#24292e}
.colorful .soundcloud a{background:linear-gradient(#ff7400,#ff3400)}
.colorful .behance a{color:#191919}
.colorful .digg a{color:#1b1a19}
.colorful .delicious a{color:#0076e8}
.colorful .codepen a{color:#000}
