/* --- YUSUF'S SYNAPTIC BRANDING & RESEARCH JOURNAL LAYOUT --- */

/* 1. CORE VARIABLES */
:root {
  --main-brand: #1a237e;      /* Theory (Indigo) */
  --accent-link: #00e5ff;     /* Practical (Cyan) */
  --body-bg: #ffffff;         /* Background */
  --main-text: #1f2937;       /* Readability */
  --mist: #f1f5f9;            /* Glacial Mist */
}

/* 2. GLOBAL SETTINGS & FINE TEXT */
body, p, .post-body {
  background-color: var(--body-bg) !important;
  color: var(--main-text) !important;
  font-family: var(--body-font), sans-serif !important;
  font-weight: 300 !important; /* Text optimization */
  font-size: 16px !important;
  line-height: 1.8 !important; 
  letter-spacing: 0.01em;
  -webkit-font-smoothing: antialiased;
}

/* 3. LOGO & HEADER HARMONY */
.header-inner, .nav-menu {
  display: flex !important;
  align-items: center !important;
  height: 70px !important; 
  overflow: hidden; 
}

/* Specific fix to kill the box & optimize search result */
#header-inner img, 
.header-logo img, 
.header-logo a {
    max-height: 50px !important;
    width: auto !important;
    margin: 5px 10px !important;
    object-fit: contain;
    border: none !important;      /* Forces border off */
    outline: none !important;     /* Forces outline off */
    box-shadow: none !important;  /* Forces shadow off */
    padding: 0 !important;        /* Removes extra spacing */
    background: transparent !important;
    display: inline-block !important;
}

/* 4. HERO SECTION (The Portal) */
.hero-inner {
  background: linear-gradient(135deg, #00b8d4 0%, #1a237e 100%) !important;
  padding: 80px 0 !important;
}

.hero-title {
  font-size: 52px !important; 
  font-weight: 800 !important;
  color: #ffffff !important;
  line-height: 1.2;
  margin-bottom: 25px;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
}

.hero-title::before {
  content: "🧬";
  margin-right: 15px;
  font-size: 0.85em;
  vertical-align: middle;
  color: var(--accent-link);
}

.hero-description {
  font-size: 24px !important; 
  font-weight: 600 !important;
  color: #f1f5f9 !important;
  background: rgba(26, 35, 126, 0.25);
  padding: 15px 25px;
  border-left: 6px solid var(--accent-link);
  display: inline-block;
  line-height: 1.4;
  border-radius: 0 12px 12px 0;
  backdrop-filter: blur(5px);
}

/* 5. POST CARDS & BODY */
.post-outer {
  border: 1px solid #e2e8f0 !important;
  border-radius: 12px !important;
  padding: 30px !important;
  margin-bottom: 40px !important;
  transition: all 0.3s ease;
  background: #ffffff;
}

.post-outer:hover {
  transform: translateY(-5px);
  box-shadow: 0 12px 30px rgba(26, 35, 126, 0.08) !important;
}

.post-body {
  font-size: 18px !important;
  color: #2d3748 !important;
  line-height: 1.9 !important;
  text-align: justify;
}

/* 6. SIDEBAR & WIDGETS */
.sidebar .widget {
  background: #ffffff;
  border: 1px solid var(--mist);
  border-radius: 12px;
  padding: 25px !important;
  margin-bottom: 35px !important;
}

.sidebar .Image img {
  border: 3px solid var(--mist);
  padding: 5px;
  transition: all 0.4s ease;
}

.sidebar .Image img:hover {
  border-color: var(--accent-link);
  transform: scale(1.02);
}

/* 7. RESPONSIVE OPTIMIZATIONS (The Fixes) */
@media screen and (max-width: 768px) {
  .header-inner { height: 60px !important; }
  .header-logo img { max-height: 40px !important; }

  .hero-title { font-size: 32px !important; }
  .hero-description { font-size: 18px !important; padding: 10px 15px; }

  .post-outer { 
    padding: 15px !important; 
    margin-left: 5px !important; 
    margin-right: 5px !important; 
  }

  .post-body { text-align: left; } /* Better for small screens */
}

/* 8. CATEGORY CARDS BASE DESIGN */
.category-item {
    border-radius: 15px;
    padding: 30px 20px;
    text-align: center;
    transition: all 0.3s ease;
    height: 100%;
    border: 1px solid rgba(0,0,0,0.05);
    box-shadow: 0 4px 10px rgba(0,0,0,0.02);
}

.category-item:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 20px rgba(0,0,0,0.08);
}

/* Category Icon Blob Wrap */
.category-icon-wrap {
    width: 100px;
    height: 100px;
    margin: 0 auto 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 40% 60% 70% 30% / 40% 50% 60% 50%; /* Organic Shape */
}

.category-icon-wrap img {
    width: 70px;
    height: 70px;
    object-fit: contain;
}

.category-title {
    font-size: 18px;
    font-weight: 700;
    margin-bottom: 10px;
    color: #333;
}

.category-desc {
    font-size: 13px;
    color: #666;
    line-height: 1.6;
}

/* --- Category Background Colors --- */

/* 1. Biostatistics & Research */
.cat-biostats { background-color: #f4f9f9; }
.cat-biostats .category-icon-wrap { background-color: rgba(200, 230, 230, 0.4); }

/* 2. Ecology & Environment */
.cat-ecology { background-color: #f3f7fd; }
.cat-ecology .category-icon-wrap { background-color: rgba(210, 233, 255, 0.4); }

/* 3. Human Behaviour */
.cat-human { background-color: #fdf5f6; }
.cat-human .category-icon-wrap { background-color: rgba(255, 210, 218, 0.4); }

/* 4. Leadership Behind Biology */
.cat-leadership { background-color: #f0fbfc; }
.cat-leadership .category-icon-wrap { background-color: rgba(200, 245, 250, 0.4); }

/* 5. Random Thoughts */
.cat-random { background-color: #f7f5ff; }
.cat-random .category-icon-wrap { background-color: rgba(230, 220, 255, 0.4); }

/* 6. Practical Practices */
.cat-practical { background-color: #f9fdf2; }
.cat-practical .category-icon-wrap { background-color: rgba(230, 250, 200, 0.4); }

/* --- FORMS & BUTTONS --- */
/* মেসেজ পাঠান বাটন পজিশন ফিক্স */
.contact-form-button-submit {
    margin-top: -5px !important; 
    padding: 10px 20px !important;
    background-color: #1a237e !important;
    border-radius: 4px !important;
}
}/* --- Contrast Fixes for Accessibility (Level AA) --- */

/* Note: Post Dates and Excerpts are handled natively by your :root variables! */

/* Fix for Link color contrast if needed */
.entry-category a, .post-labels a {
    color: #0056b3 !important; /* Slightly darker blue for better contrast */
}

/* Fix for Dark Footer Sections (based on your #444444 error) */
#footer-widget-container, .footer-copyright, .footer-sec-text {
    color: #e0e0e0 !important;
}

/* Ensure placeholder/faint text is readable */
::placeholder {
    color: #757575 !important;
}

/* --- ACCESSIBILITY SAFETY OVERRIDE --- */
/* Ensures Three-Dot Bar and Menu Icons are always visible (Contrast 4.5:1+) */

/* Targets the Three-Dot/Hamburger icon */
.show-menu::before, .show-menu::after, .show-menu {
    border-color: #ffffff !important; 
    color: #ffffff !important;
}

/* Targets the Search icon in the bar */
.show-search i, .show-search svg {
    color: #ffffff !important;
    fill: #ffffff !important;
}

/* Fix for the #444444 error found in your screenshot */
/* This ensures that if text is on a dark bar, it stays bright */
.nav-menu .menu-item a, .nav-search .search-input {
    color: #ffffff !important;
}

/* Ensure any "faint" dividers in the menu bar are visible */
.menu-sep {
    border-color: rgba(255,255,255,0.3) !important;
}

/* --- Post Experience Enhancements --- */
.item-post .post-body {
  max-width: 78ch;
  margin-inline: auto;
  padding: 0 4px;
}

.item-post .post-body p,
.item-post .post-body li {
  text-wrap: pretty;
}

.item-post .post-body h2,
.item-post .post-body h3,
.item-post .post-body h4 {
  scroll-margin-top: 95px;
  border-left: 4px solid var(--main-link-color);
  padding-left: 10px;
}

.item-post .post-body blockquote {
  border-left: 4px solid var(--main-link-color);
  background: color-mix(in srgb, var(--main-link-color) 8%, #fff);
  margin: 20px 0;
  padding: 14px 16px;
  border-radius: 8px;
}

.item-post .post-body pre,
.item-post .post-body code {
  font-family: 'Fira Code', 'Consolas', monospace;
}

.item-post .post-body pre {
  overflow-x: auto;
  padding: 14px;
  border-radius: 10px;
  background: #0f172a;
  color: #e2e8f0;
}

.item-post .post-body img:not(.emoji) {
  border-radius: 12px;
  box-shadow: 0 10px 25px rgba(15, 23, 42, 0.12);
}

.dark .item-post .post-body blockquote {
  background: rgba(148, 163, 184, 0.14);
}

@media screen and (max-width: 768px) {
  .item-post .post-body {
    max-width: 100%;
    font-size: 16px !important;
    line-height: 1.8 !important;
  }
}
/* --- Contrast Fixes Phase 2: Specific Failing Elements --- */

/* 1. Post Author and Super Category Tags */
/* Forces the faint text to be a readable dark gray on light backgrounds */
.post-author, 
.post-author a, 
.super-category, 
.super-category a {
    color: #555555 !important;
}

/* 2. "Load More" Pagination Button */
/* Ensures the text and border are dark enough to be seen clearly */
.blog-pager-older-link.load-more, 
#load-more-link {
    color: #555555 !important;
    border-color: #757575 !important; 
}

/* 3. Cookies "Ok, Got it!" Button */
/* Cookie banners vary, so this forces a universally accessible solid button: White text on Dark Blue */
.cookies-bt {
    color: #ffffff !important;
    background-color: #0056b3 !important; 
    border: 1px solid #0056b3 !important;
    font-weight: bold !important;
}

