body.script:
//
var lazyLoadAds = false;
// Listen for scroll, mouse movement, or touch (for mobile)
window.addEventListener("scroll", loadAdsOnce);
window.addEventListener("mousemove", loadAdsOnce);
window.addEventListener("touchstart", loadAdsOnce);

function loadAdsOnce() {
    if (lazyLoadAds === false) {
        (function() {
            var adScript = document.createElement('script');
            adScript.src = 'https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-9144658795059352';
            adScript.async = true;
            adScript.crossOrigin = 'anonymous';
            document.head.appendChild(adScript);
        })();
        lazyLoadAds = true;
        // Remove listeners once ads are loaded to save memory
        window.removeEventListener("scroll", loadAdsOnce);
        window.removeEventListener("mousemove", loadAdsOnce);
        window.removeEventListener("touchstart", loadAdsOnce);
    }
}
